import json
import logging
import boto3

# IAM Role with S3 Read/Write, SNS Publish, CloudWatch Logs permissions
# role:arn:aws:iam::123456789012:role/lambda_role

def lambda_handler(event, context):
    # Get S3 event data
    s3_event = event['Records'][0]
    bucket_name = s3_event['s3']['bucket']['name']
    file_name = s3_event['s3']['object']['key']

    # Read image from S3
    s3_client = boto3.client('s3')
    image_data = s3_client.get_object(Bucket=bucket_name, Key=file_name)['Body'].read()

    # Perform image processing here (e.g., resizing, filtering)

    # Write results back to S3
    processed_file_name = f"processed_{file_name}"
    s3_client.put_object(Bucket=bucket_name, Key=processed_file_name, Body=image_data)

    # Send notification via SNS
    sns_client = boto3.client('sns')
    sns_client.publish(TopicArn='arn:aws:sns:us-east-1:123456789012:image_processing_topic', Message=f"Image {file_name} processed successfully.")

    # Log to CloudWatch
    logger = logging.getLogger()
    logger.info(f"Image {file_name} processed successfully.")

    return {
        'statusCode': 200,
        'body': json.dumps('Image processed successfully.')
    }